html:
{%- set program_name = frappe.db.get_value('Program', doc.program, 'program_name') or doc.program -%}
{%- set student_name = frappe.db.get_value('Student', doc.student, 'student_name') -%}
<div class="seminary-diploma">
  <style>
    .seminary-diploma { font-family: 'Garamond', 'EB Garamond', Georgia, serif; color: #1f2937; padding: 48px 56px; border: 4px double #1f2937; }
    .seminary-diploma .header { text-align: center; margin-bottom: 32px; }
    .seminary-diploma .school { font-size: 28px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; }
    .seminary-diploma .preamble { text-align: center; font-size: 16px; margin: 24px 0 8px 0; font-style: italic; }
    .seminary-diploma .name { text-align: center; font-size: 36px; font-weight: 700; margin: 8px 0 24px 0; letter-spacing: 1px; }
    .seminary-diploma .body { text-align: center; font-size: 16px; line-height: 1.6; max-width: 640px; margin: 0 auto; }
    .seminary-diploma .program { font-weight: 600; }
    .seminary-diploma .meta { display: flex; justify-content: space-between; margin-top: 56px; font-size: 13px; }
    .seminary-diploma .meta .col { flex: 1; text-align: center; }
    .seminary-diploma .meta .label { color: #6b7280; text-transform: uppercase; font-size: 10px; letter-spacing: 1px; margin-bottom: 4px; }
    .seminary-diploma .signatures { display: flex; justify-content: space-between; margin-top: 48px; padding: 0 32px; }
    .seminary-diploma .signatures .sig { flex: 1; text-align: center; padding: 0 16px; }
    .seminary-diploma .signatures .line { border-top: 1px solid #1f2937; padding-top: 6px; font-size: 12px; color: #6b7280; }
    .seminary-diploma .footer { margin-top: 40px; text-align: center; font-size: 10px; color: #9ca3af; }
    .seminary-diploma .footer .hash { font-family: 'Courier New', monospace; letter-spacing: 0.5px; }
  </style>

  {% if letter_head and not no_letterhead %}<div class="letter-head" style="text-align:center; margin-bottom: 16px;">{{ letter_head }}</div>{% endif %}

  <div class="header">
    <div class="school">{{ frappe.defaults.get_defaults().company or _('The Seminary') }}</div>
  </div>

  <div class="preamble">{{ _('This is to certify that') }}</div>
  <div class="name">{{ doc.legal_name }}</div>

  <div class="body">
    {{ _('has successfully completed all requirements of the') }}
    <div class="program" style="margin: 6px 0;">{{ program_name }}</div>
    {% if doc.expected_graduation_date %}
      {{ _('and is hereby awarded this diploma on') }}
      <strong>{{ frappe.utils.formatdate(doc.expected_graduation_date, 'long') }}</strong>.
    {% else %}
      {{ _('and is hereby awarded this diploma.') }}
    {% endif %}
  </div>

  <div class="signatures">
    <div class="sig"><div class="line">{{ _('President') }}</div></div>
    <div class="sig"><div class="line">{{ _('Registrar') }}</div></div>
  </div>

  <div class="meta">
    <div class="col">
      <div class="label">{{ _('Diploma Serial') }}</div>
      <div>{{ doc.diploma_serial }}</div>
    </div>
    <div class="col">
      <div class="label">{{ _('Issued') }}</div>
      <div>{{ frappe.utils.formatdate(doc.issued_on, 'long') }}</div>
    </div>
  </div>

  <div class="footer">
    {{ _('Verification ID') }}: <span class="hash">{{ doc.verification_hash or doc.name }}</span>
    {% if doc.revoked %}<div style="color:#b91c1c; font-weight:600; margin-top:6px;">{{ _('REVOKED') }}: {{ doc.revocation_reason or '' }}</div>{% endif %}
  </div>
</div>
